import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string to handle cases where '\n' appears literally
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Replace literal "\\n" and "\\r" with spaces, also normalize real newlines
        data = data.replace("\\n", " ").replace("\\r", " ");
        data = data.replace('\n', ' ').replace('\r', ' ');
        StringTokenizer st = new StringTokenizer(data);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            if (!st.hasMoreTokens()) break;
            int N = Integer.parseInt(st.nextToken());
            int X = Integer.parseInt(st.nextToken());
            boolean found = false;
            // There are N-1 edges (if N>1)
            for (int i = 0; i < N - 1; i++) {
                int parent = Integer.parseInt(st.nextToken());
                int child = Integer.parseInt(st.nextToken());
                // direction token (L or R), we just consume it
                if (st.hasMoreTokens()) st.nextToken();
                if (parent == X || child == X) {
                    found = true;
                }
            }
            out.append(found ? "YES" : "NO");
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

